    const winRate = totalBets > 0 ? ((wins / totalBets) * 100).toFixed(1) : 0;
    const drawdown = Math.min(0, ...state.history.map(h => h.runningBalance));

    elements.statBanker.textContent = bankers;
    elements.statPlayer.textContent = players;
    elements.statWinrate.textContent = `${winRate}%`;
    elements.statDrawdown.textContent = `${drawdown} Units`;

    // Chart
    if (chart) {
        const chartData = [{ x: 0, y: 0 }];
        let validSteps = 0;
        state.history.forEach(h => {
            if (h.winner !== Winner.TIE) {
                validSteps++;
                chartData.push({ x: validSteps, y: h.runningBalance });
            }
        });
        chart.data.datasets[0].data = chartData;
        chart.update();
    }

    // Road (Only update if visible for perf)
    if (state.activeTab === 'road') renderBigRoad();

    // Log (Only first few rows or full if visible)
    if (state.activeTab === 'log') renderLog();
    elements.logCount.textContent = `${state.history.length} hands`;
}

function renderLog() {
    const html = state.history.slice().reverse().map(h => `
        <tr class="border-b border-theme-border hover:bg-white/5 transition-colors">
            <td class="p-3 font-mono text-gray-600">${h.id}</td>
            <td class="p-3">
                <span class="font-bold mr-2 ${h.winner === Winner.PLAYER ? 'text-blue-500' : h.winner === Winner.BANKER ? 'text-red-500' : 'text-green-500'}">
                    ${h.winner[0]}
                </span>
                <span class="text-[10px] px-1.5 py-0.5 font-bold rounded-sm ${h.outcome === 'WIN' ? 'bg-theme-brand text-black' : h.outcome === 'LOSS' ? 'bg-red-500 text-white' : 'bg-gray-800 text-gray-400'}">
                    ${h.outcome}
                </span>
            </td>
            <td class="p-3 text-center font-mono">${h.playerScore} - ${h.bankerScore}</td>
            <td class="p-3 text-center font-mono">${Math.abs(h.playerScore - h.bankerScore)}</td>
            <td class="p-3 text-center font-bold">
                ${h.betPlaced ? `<span class="${h.betPlaced === Winner.PLAYER ? 'text-blue-500' : 'text-red-500'}">${h.betPlaced[0]}</span>` : '-'}
            </td>
            <td class="p-3 text-right font-mono font-bold ${h.runningBalance > 0 ? 'text-theme-brand' : h.runningBalance < 0 ? 'text-red-500' : 'text-gray-500'}">
                ${h.runningBalance > 0 ? '+' : ''}${h.runningBalance}
            </td>
        </tr>
    `).join('');
    elements.logBody.innerHTML = html;
}

// --- Simulation Logic ---
function dealHand() {
    if (!engine.hasCards()) {
        stopSim();
        return;
    }
    const result = engine.dealNextHand(state.history, state.balance);
    if (!result) {
        stopSim();
        return;
    }
    state.history.push(result);
    state.balance = result.runningBalance;
    updateUI();
    if (state.active) timer = setTimeout(dealHand, state.speed);
}

function startSim() {
    state.active = true;
    elements.iconPlay.classList.add('hidden');
    elements.iconStop.classList.remove('hidden');
    dealHand();
}

function stopSim() {
    state.active = false;
    if (timer) clearTimeout(timer);
    elements.iconPlay.classList.remove('hidden');
    elements.iconStop.classList.add('hidden');
}

function downloadChart() {
  if (!chart) return;
  const canvas = document.getElementById('chart-performance');
  if (!canvas) return;

  // Create a temporary canvas with background to ensure it's not transparent
  const tempCanvas = document.createElement('canvas');
  tempCanvas.width = canvas.width;
  tempCanvas.height = canvas.height;
  const tempCtx = tempCanvas.getContext('2d');

  tempCtx.fillStyle = '#0a0a0a';
  tempCtx.fillRect(0, 0, tempCanvas.width, tempCanvas.height);
  tempCtx.drawImage(canvas, 0, 0);

  const link = document.createElement('a');
  link.download = `d5-performance-vanilla-${Date.now()}.png`;
  link.href = tempCanvas.toDataURL('image/png');
  link.click();
}

// --- Events ---
elements.btnToggle.addEventListener('click', () => {
    state.active ? stopSim() : startSim();
});

elements.btnFF.addEventListener('click', () => {
    stopSim();
    while (engine.hasCards()) {
        const result = engine.dealNextHand(state.history, state.balance);
        if (!result) break;
        state.history.push(result);
        state.balance = result.runningBalance;
    }
    updateUI();
});

elements.btnReset.addEventListener('click', () => {
    stopSim();
    engine.initShoe();
    state.history = [];
    state.balance = 0;
    updateUI();
});

elements.simSpeed.addEventListener('change', (e) => {
    state.speed = parseInt(e.target.value);
});

elements.btnDownloadChart.addEventListener('click', downloadChart);

// Tab Switching
document.querySelectorAll('.tab-btn').forEach(btn => {
    btn.addEventListener('click', () => {
        const tab = btn.dataset.tab;
        state.activeTab = tab;

        document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active-tab'));
        btn.classList.add('active-tab');

        document.querySelectorAll('.tab-panel').forEach(p => p.classList.add('hidden'));
        document.getElementById(`panel-${tab}`).classList.remove('hidden');

        updateUI();
    });
});

// Init
initChart();
updateUI();

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { BaccaratEngine } from './services/baccaratEngine';
import { HandResult, SimulationState, Winner } from './types';
import PerformanceChart from './components/PerformanceChart';
import BigRoad from './components/BigRoad';

const App: React.FC = () => {
  const [state, setState] = useState<SimulationState>({
    active: false,
    history: [],
    balance: 0,
    speed: 1000,
  });

  const [activeTab, setActiveTab] = useState<'perf' | 'road' | 'log'>('perf');

  const engineRef = useRef(new BaccaratEngine());
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const stopSimulation = useCallback(() => {
    if (timerRef.current) {
      clearTimeout(timerRef.current);
      timerRef.current = null;
    }
    setState(prev => ({ ...prev, active: false }));
  }, []);

  const dealOneHand = useCallback(() => {
    const engine = engineRef.current;
    if (!engine.hasCards()) {
      stopSimulation();
      return;
    }

    setState(prev => {
      const result = engine.dealNextHand(prev.history, prev.balance);
      if (!result) {
        stopSimulation();
        return prev;
      }
      return {
        ...prev,
        history: [...prev.history, result],
        balance: result.runningBalance,
      };
    });
  }, [stopSimulation]);

  const startSimulation = useCallback(() => {
    setState(prev => ({ ...prev, active: true }));
  }, []);

  const resetShoe = useCallback(() => {
    stopSimulation();
    engineRef.current.initShoe();
    setState(prev => ({
      ...prev,
      history: [],
      balance: 0,
      active: false,
    }));
  }, [stopSimulation]);

  const fastForward = useCallback(() => {
    stopSimulation();
    const engine = engineRef.current;

    setState(prev => {
      let currentBalance = prev.balance;
      const newHistory = [...prev.history];

      while (engine.hasCards()) {
        const result = engine.dealNextHand(newHistory, currentBalance);
        if (!result) break;
        newHistory.push(result);
        currentBalance = result.runningBalance;
      }

      return {
        ...prev,
        history: newHistory,
        balance: currentBalance,
        active: false,
      };
    });
  }, [stopSimulation]);

  useEffect(() => {
    if (state.active) {
      timerRef.current = setTimeout(dealOneHand, state.speed);
    } else if (timerRef.current) {
      clearTimeout(timerRef.current);
    }
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [state.active, state.history.length, state.speed, dealOneHand]);

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-theme-base font-sans selection:bg-theme-brand selection:text-black">
      {/* Header */}
      <header className="flex-shrink-0 border-b border-theme-border bg-theme-panel p-4 flex items-center justify-between z-10">
        <div className="flex items-center gap-4">
          <h1 className="text-lg font-black tracking-tighter text-white uppercase italic">
            D5<span className="text-theme-brand">SIM</span>
          </h1>
        </div>

        <div className="flex items-center gap-2">
          <select 
            value={state.speed} 
            onChange={(e) => setState(prev => ({ ...prev, speed: parseInt(e.target.value) }))}
            className="bg-black border border-theme-border text-xs text-gray-400 p-1 px-2 focus:outline-none focus:border-theme-brand rounded-sm"
          >
            <option value={1500}>Speed: Slow</option>
            <option value={800}>Speed: Normal</option>
            <option value={100}>Speed: Turbo</option>
          </select>

          <div className="flex bg-black border border-theme-border h-8 overflow-hidden rounded-sm">
            <button 
              onClick={() => state.active ? stopSimulation() : startSimulation()}
              className={`px-6 flex items-center justify-center transition-colors ${state.active ? 'text-red-500 hover:bg-red-500/10' : 'text-theme-control hover:bg-theme-control/10'}`}
            >
              {state.active ? (
                <svg className="w-4 h-4 fill-current" viewBox="0 0 24 24"><rect x="6" y="4" width="12" height="16"/></svg>
              ) : (
                <svg className="w-4 h-4 fill-current" viewBox="0 0 24 24"><polygon points="5 3 19 12 5 21 5 3"/></svg>
              )}
            </button>
            <button 
              onClick={fastForward}
              className="px-4 flex items-center justify-center border-l border-theme-border text-gray-400 hover:text-theme-control transition-colors"
              title="Fast Forward to End"
            >
              <svg className="w-4 h-4 fill-current" viewBox="0 0 24 24">
                <polygon points="13 19 22 12 13 5 13 19"/><polygon points="2 19 11 12 2 5 2 19"/>
              </svg>
            </button>
            <button 
              onClick={resetShoe}
              className="px-4 flex items-center justify-center border-l border-theme-border text-gray-400 hover:text-red-500 transition-colors"
              title="Reset Shoe"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"/></svg>
            </button>
          </div>
        </div>
      </header>

      {/* Main Area */}
      <main className="flex-grow flex flex-col md:flex-row overflow-hidden">
        {/* Sidebar Tabs */}
        <nav className="flex-shrink-0 bg-theme-panel border-r border-theme-border flex md:flex-col overflow-auto md:w-16">
          {[
            { id: 'perf', icon: 'M13 7h8m0 0v8m0-8l-8 8-4-4-6 6', label: 'Perf' },
            { id: 'road', icon: 'M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6zM4 16a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2v-2zM14 16a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2v-2z', label: 'Road' },
            { id: 'log', icon: 'M4 6h16M4 12h16m-7 6h7', label: 'Log' },
          ].map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex-1 md:flex-none h-16 flex flex-col items-center justify-center transition-all relative ${
                activeTab === tab.id ? 'text-theme-brand' : 'text-gray-500 hover:text-gray-300'
