// --- Chart Initialization ---
function initChart() {
    const ctx = document.getElementById('chart-performance').getContext('2d');
    chart = new Chart(ctx, {
        type: 'line',
        data: {
            datasets: [{
                label: 'Units',
                data: [{ x: 0, y: 0 }],
